   941→// AI interviewer conducts a conversational interview turn
   942→async function conductInterviewTurn(conversation, baseQuestions, currentQuestionIndex, targetRole, options = {}) {
   943→  // Send last 12 turns for better context on follow-ups
   944→  const recentConvo = conversation.slice(-12);
   945→  const convoText = recentConvo.map(turn => {
   946→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
   947→    return `CANDIDATE: ${turn.text}`;
   948→  }).join('\n\n');
   949→
   950→  const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
   951→  const followUpCount = conversation.filter(t => t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')).length;
   952→  const remainingQuestions = baseQuestions.slice(currentQuestionIndex);
   953→  const nextPlannedQuestion = remainingQuestions.length > 0
   954→    ? remainingQuestions[0].question_text
   955→    : null;
   956→
   957→  // Count consecutive follow-ups on the current topic
   958→  let consecutiveFollowUps = 0;
   959→  for (let i = conversation.length - 1; i >= 0; i--) {
   960→    const t = conversation[i];
   961→    if (t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')) {
   962→      consecutiveFollowUps++;
   963→    } else if (t.role === 'interviewer' && t.action === 'transition') {
   964→      break;
   965→    } else if (t.role === 'candidate') {
   966→      continue; // skip candidate turns when counting
   967→    }
   968→  }
   969→
   970→  const prompt = `You are conducting a mock interview for a "${targetRole}" position. You have ${remainingQuestions.length} planned questions remaining.
   971→
   972→CONVERSATION SO FAR:
   973→${convoText}
   974→
   975→${nextPlannedQuestion ? `NEXT PLANNED QUESTION (use when ready to move on): "${nextPlannedQuestion}"` : 'All planned questions covered.'}
   976→
   977→FOLLOW-UP COUNT on current topic: ${consecutiveFollowUps}
   978→
   979→YOUR TASK: Act like a real interviewer. After the candidate answers:
   980→
   981→1. **FOLLOW UP** if the answer is:
   982→   - Vague or surface-level ("I worked on a project" → ask WHAT project, what was the challenge)
   983→   - Missing specifics (no metrics, no concrete examples, no details about their role)
   984→   - Interesting but unexplored (they mentioned something worth digging into)
   985→   - Missing the "so what" (they described what happened but not the impact/result)
   986→   You can ask MULTIPLE follow-ups on the same topic. Keep probing until you have real depth.
   987→
   988→2. **TRANSITION** to the next planned question when:
   989→   - The candidate gave a thorough, specific answer with concrete examples
   990→   - You've already asked 2-3 follow-ups and have sufficient depth
   991→   - The candidate clearly has nothing more to add on this topic
   992→
   993→3. **WRAP UP** when: ${candidateTurnCount >= 6 ? 'You feel you have enough data (6+ exchanges completed)' : 'NOT YET — keep interviewing, only ' + candidateTurnCount + ' exchanges so far'}
   994→
   995→React to their answer specifically (1-2 sentences — reference something concrete they said, NOT generic filler like "Thank you for that response" or "That's helpful"). Show you actually listened. Example good reactions: "That 40% improvement in pipeline throughput is impressive — how did you measure that?" or "Interesting that you chose to refactor first rather than ship the feature." Example bad reactions: "Thank you for sharing that." or "That's great, thanks."
   996→
   997→Return JSON: {"reaction":"1-2 sentences referencing SPECIFIC details from their answer","action":"follow_up|challenge|transition|wrap_up","question":"your next question","score_hint":1-10,"notes":"brief note on answer quality"}`;
   998→
   999→  const result = await chat(prompt, {
  1000→    system: `You are Alex, an experienced ${targetRole} interviewer. You conduct interviews like a real person — curious, attentive, and thorough. You don't just read from a script. When a candidate gives a vague answer, you probe deeper. When they mention something interesting, you explore it. You ask follow-up questions naturally, like "Tell me more about that" or "What specifically was your role in that?" or "How did you measure success?" You only move to the next planned question when you're genuinely satisfied with the depth of their answer. Always return valid JSON only.`,
  1001→    maxTokens: 1024,
  1002→    subscriptionId: options.subscriptionId
  1003→  });
  1004→
  1005→  const parsed = safeParseJSON(result);
  1006→  if (parsed) return parsed;
  1007→  throw new Error('Failed to generate interview turn — could not parse LLM response');
  1008→}
