   466→    function renderPipelineCard(app, currentStage) {
   467→      const matchClass = app.match_score >= 80 ? 'excellent' :
   468→                         app.match_score >= 60 ? 'good' :
   469→                         app.match_score >= 40 ? 'fair' : 'poor';
   470→
   471→      // Determine next stage
   472→      const stageOrder = ['applied', 'screening', 'reviewing', 'interviewed', 'offered', 'hired'];
   473→      const currentIdx = stageOrder.indexOf(currentStage);
   474→      const nextStage = currentIdx < stageOrder.length - 1 ? stageOrder[currentIdx + 1] : null;
   475→      const nextMeta = nextStage ? STAGE_META[nextStage] : null;
   476→
   477→      return `
   478→        <div class="pipeline-card" data-app-id="${app.id}">
   479→          <div class="pipeline-card-top">
   480→            <div class="pipeline-candidate">
   481→              <div class="pipeline-avatar">${(app.candidate_name || 'U')[0].toUpperCase()}</div>
   482→              <div>
   483→                <div class="pipeline-name">${app.candidate_name || 'Unknown'}</div>
   484→                <div class="pipeline-email">${app.candidate_email || ''}</div>
   485→              </div>
   486→            </div>
   487→            ${app.match_score ? `<div class="pipeline-match ${matchClass}">${app.match_score}%</div>` : ''}
   488→          </div>
   489→          <div class="pipeline-card-meta">
   490→            ${app.current_omniscore ? `<span class="p-badge omni">${app.current_omniscore} OS</span>` : ''}
   491→            ${app.verified_skills_count > 0 ? `<span class="p-badge skill">✓ ${app.verified_skills_count} Skills</span>` : ''}
   492→            ${app.best_interview_score ? `<span class="p-badge interview">🎤 ${app.best_interview_score}</span>` : ''}
   493→          </div>
   494→          <div class="pipeline-card-actions">
   495→            ${nextStage ? `<button class="btn btn-primary btn-xs" onclick="moveToStage(${app.id}, '${nextStage}')">→ ${nextMeta.label}</button>` : ''}
   496→            ${currentStage !== 'rejected' ? `<button class="btn btn-ghost btn-xs danger" onclick="moveToStage(${app.id}, 'rejected')">Reject</button>` : ''}
   497→          </div>
   498→        </div>
   499→      `;
   500→    }
