   502→    async function moveToStage(appId, newStatus) {
   503→      try {
   504→        const result = await apiCall(`/recruiter/applications/${appId}/status`, {
   505→          method: 'PUT',
   506→          body: JSON.stringify({ status: newStatus })
   507→        });
   508→        if (result.success && currentJob) {
   509→          loadPipeline(currentJob);
   510→          loadApplications(); // Refresh list view data too
   511→        }
   512→      } catch (err) {
   513→        alert('Failed to move candidate');
   514→      }
   515→    }
