   517→    // ============= LIST VIEW RENDER =============
   518→    function renderApplications() {
   519→      const container = document.getElementById('applications-list');
   520→
   521→      let filtered = applications;
   522→      if (currentFilter !== 'all') {
   523→        filtered = filtered.filter(a => a.status === currentFilter);
   524→      }
   525→      if (currentJob) {
   526→        filtered = filtered.filter(a => a.job_id == currentJob);
   527→      }
   528→
   529→      if (filtered.length === 0) {
   530→        container.innerHTML = `
   531→          <div class="empty-state">
   532→            <p>No applications found</p>
   533→            <a href="/job-create.html" class="btn btn-primary btn-sm">Post a Job</a>
   534→          </div>
   535→        `;
   536→        return;
   537→      }
   538→
   539→      container.innerHTML = filtered.map(app => {
   540→        const answers = typeof app.screening_answers === 'string' ? JSON.parse(app.screening_answers || '{}') : (app.screening_answers || {});
   541→        const questions = typeof app.screening_questions === 'string' ? JSON.parse(app.screening_questions || '[]') : (app.screening_questions || []);
   542→
   543→        let screeningHTML = '';
   544→        if (questions.length > 0 && Object.keys(answers).length > 0) {
   545→          screeningHTML = `
   546→            <div class="screening-answers">
   547→              <div class="screening-label">📋 Screening Answers</div>
   548→              <div class="screening-grid">
   549→                ${questions.map(q => {
   550→                  const ans = answers[q.id] || '-';
   551→                  return `<div class="screening-item">
   552→                    <span class="sq-q">${q.question}</span>
   553→                    <span class="sq-a ${q.type === 'yes_no' ? (ans === 'yes' ? 'sq-yes' : 'sq-no') : ''}">${ans}</span>
   554→                  </div>`;
   555→                }).join('')}
   556→              </div>
   557→            </div>`;
   558→        }
   559→
   560→        let insightsHTML = '';
   561→        if (app.verified_skills_count > 0 || app.best_interview_score || app.completed_interviews > 0) {
   562→          insightsHTML = `<div class="candidate-insights">
   563→            ${app.verified_skills_count > 0 ? `<span class="insight-badge skill-badge">✓ ${app.verified_skills_count} Verified Skill${app.verified_skills_count > 1 ? 's' : ''}</span>` : ''}
   564→            ${app.best_interview_score ? `<span class="insight-badge interview-badge">🎤 Best: ${app.best_interview_score}/10</span>` : ''}
   565→            ${app.completed_interviews > 0 ? `<span class="insight-badge practice-badge">📝 ${app.completed_interviews} Mocks</span>` : ''}
   566→          </div>`;
   567→        }
   568→
   569→        const matchClass = app.match_score >= 80 ? 'excellent' : app.match_score >= 60 ? 'good' : app.match_score >= 40 ? 'fair' : 'poor';
   570→
   571→        return `
   572→        <div class="application-card">
   573→          <div class="application-header">
   574→            <div class="candidate-info">
   575→              <input type="checkbox" class="app-checkbox" id="cb-${app.id}" onclick="event.stopPropagation(); toggleSelect(${app.id})" ${selectedIds.has(app.id) ? 'checked' : ''}>
   576→              <div class="candidate-avatar">${(app.candidate_name || 'U').charAt(0).toUpperCase()}</div>
   577→              <div class="candidate-details">
   578→                <h3>${app.candidate_name || 'Unknown'}</h3>
   579→                <p>${app.job_title || 'Position'}</p>
   580→              </div>
   581→            </div>
   582→            <div class="application-meta">
   583→              ${app.match_score ? `<span class="match-badge ${matchClass}">🎯 ${app.match_score}%</span>` : ''}
   584→              ${app.omniscore_at_apply ? `<span class="omniscore-badge">${app.omniscore_at_apply} OS</span>` : ''}
   585→              <span class="status-badge ${app.status}">${formatStatusLabel(app.status)}</span>
   586→            </div>
   587→          </div>
   588→          <div class="application-body">
   589→            <div class="application-info">
   590→              <span class="info-item">📧 ${app.candidate_email || 'No email'}</span>
   591→              <span class="info-item">📅 ${formatDate(app.applied_at)}</span>
   592→            </div>
   593→            ${insightsHTML}
   594→            ${app.cover_letter ? `<p class="cover-letter-preview">${app.cover_letter.substring(0, 150)}...</p>` : ''}
   595→            ${screeningHTML}
   596→          </div>
   597→          <div class="application-actions">
   598→            <select class="quick-status-select" onchange="updateStatus(${app.id}, this.value); this.value='';">
   599→              <option value="">Move to...</option>
   600→              <option value="screening" ${app.status === 'screening' ? 'disabled' : ''}>🔍 Screening</option>
   601→              <option value="reviewing" ${app.status === 'reviewing' ? 'disabled' : ''}>👀 Reviewing</option>
   602→              <option value="interviewed" ${app.status === 'interviewed' ? 'disabled' : ''}>🎤 Interviewed</option>
   603→              <option value="offered" ${app.status === 'offered' ? 'disabled' : ''}>📄 Offered</option>
   604→              <option value="hired" ${app.status === 'hired' ? 'disabled' : ''}>🎉 Hired</option>
   605→              <option value="rejected" ${app.status === 'rejected' ? 'disabled' : ''}>✕ Rejected</option>
   606→            </select>
   607→            <button onclick="scheduleInterview(${app.id})" class="btn btn-ghost btn-sm">📅 Interview</button>
   608→            <button onclick="makeOffer(${app.id}, ${app.candidate_id}, '${(app.candidate_name || '').replace(/'/g, "\\'")}', '${(app.candidate_email || '').replace(/'/g, "\\'")}', ${app.job_id}, '${(app.job_title || '').replace(/'/g, "\\'")}')" class="btn btn-primary btn-sm" ${['offered','hired'].includes(app.status) ? 'disabled' : ''}>
   609→              Make Offer
   610→            </button>
   611→          </div>
   612→        </div>
   613→      `}).join('');
   614→    }
   615→
   616→    function formatStatusLabel(status) {
   617→      const m = { applied: 'Applied', screening: 'Screening', reviewing: 'Reviewing', interviewed: 'Interviewed', offered: 'Offered', hired: 'Hired', rejected: 'Rejected', withdrawn: 'Withdrawn' };
   618→      return m[status] || status;
   619→    }
   620→
   621→    function formatDate(dateStr) {
   622→      const date = new Date(dateStr);
   623→      const now = new Date();
   624→      const diff = now - date;
   625→      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   626→      if (days === 0) return 'Today';
   627→      if (days === 1) return 'Yesterday';
   628→      if (days < 7) return `${days}d ago`;
   629→      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
   630→    }
