   652→    // ============= MAKE OFFER =============
   653→    let currentOfferData = null;
   654→
   655→    function makeOffer(appId, candidateId, candidateName, candidateEmail, jobId, jobTitle) {
   656→      currentOfferData = { appId, candidateId, candidateName, candidateEmail, jobId, jobTitle };
   657→      document.getElementById('offer-candidate-name').textContent = candidateName;
   658→      document.getElementById('offer-job-title').value = jobTitle;
   659→      const startDate = new Date();
   660→      startDate.setDate(startDate.getDate() + 14);
   661→      document.getElementById('offer-start-date').value = startDate.toISOString().split('T')[0];
   662→      document.getElementById('offer-modal').style.display = 'flex';
   663→    }
   664→
   665→    function closeOfferModal() {
   666→      document.getElementById('offer-modal').style.display = 'none';
   667→      document.getElementById('offer-form').reset();
   668→      currentOfferData = null;
   669→    }
   670→
   671→    async function submitOffer(e) {
   672→      e.preventDefault();
   673→      if (!currentOfferData) return;
   674→
   675→      const offerData = {
   676→        candidate_id: currentOfferData.candidateId,
   677→        job_id: currentOfferData.jobId,
   678→        title: document.getElementById('offer-job-title').value,
   679→        salary: parseFloat(document.getElementById('offer-salary').value),
   680→        start_date: document.getElementById('offer-start-date').value,
   681→        benefits: document.getElementById('offer-benefits').value
   682→      };
   683→
   684→      try {
   685→        const createResult = await apiCall('/onboarding/offers', {
   686→          method: 'POST',
   687→          body: JSON.stringify(offerData)
   688→        });
   689→        if (!createResult || createResult.error) throw new Error(createResult?.error || 'Failed');
   690→
   691→        await apiCall(`/onboarding/offers/${createResult.id}/send`, { method: 'POST' });
   692→        await apiCall(`/recruiter/applications/${currentOfferData.appId}/status`, {
   693→          method: 'PUT',
   694→          body: JSON.stringify({ status: 'offered' })
   695→        });
   696→
   697→        alert('Offer sent to ' + currentOfferData.candidateName + '!');
   698→        closeOfferModal();
   699→        loadApplications();
   700→        if (currentView === 'pipeline' && currentJob) loadPipeline(currentJob);
   701→      } catch (err) {
   702→        alert('Failed to create offer: ' + err.message);
   703→      }
   704→    }
