   361→// POST /api/ai-health/prompts — create or update a prompt
   362→app.post('/api/ai-health/prompts', requireAdmin, async (req, res) => {
   363→  try {
   364→    const { slug, name, module, feature, description, systemPrompt, userTemplate, temperature, maxTokens, model, changeNote } = req.body;
