   369→    // Upsert prompt
   370→    const upsertResult = await pool.query(
   371→      `INSERT INTO ai_prompts (slug, name, module, feature, description, model)
   372→       VALUES ($1, $2, $3, $4, $5, $6)
   373→       ON CONFLICT (slug) DO UPDATE SET
   374→         name = EXCLUDED.name, module = EXCLUDED.module, feature = EXCLUDED.feature,
   375→         description = EXCLUDED.description, model = EXCLUDED.model,
   376→         current_version = ai_prompts.current_version + 1,
   377→         updated_at = NOW()
   378→       RETURNING *`,
   379→      [slug, name, module, feature || null, description || null, model || null]
   380→    );
   381→    const prompt = upsertResult.rows[0];
   382→
   383→    // Create version entry
   384→    await pool.query(
   385→      `INSERT INTO ai_prompt_versions (prompt_id, version, system_prompt, user_template, temperature, max_tokens, model, change_note)
   386→       VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
   387→      [prompt.id, prompt.current_version, systemPrompt || null, userTemplate || null,
   388→       temperature || 0.7, maxTokens || 8192, model || null, changeNote || 'Initial version']
   389→    );
