      try { const r = await pool.query(sql); return r.rows[0] || fallback; }
      catch { return fallback; }
    };
    const safeQueryRows = async (sql, fallback = []) => {
      try { const r = await pool.query(sql); return r.rows || fallback; }
      catch { return fallback; }
    };

    const [
      apps, appRecent,
      jobs,
