      safeQueryRows(`
        SELECT ja.id, ja.status, ja.applied_at, u.email as candidate_email, j.title as job_title
        FROM job_applications ja
        LEFT JOIN users u ON u.id = ja.candidate_id
        LEFT JOIN jobs j ON j.id = ja.job_id
